import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface BurndownPoint {
  day: string;
  remainingPoints: number;
}

interface SprintData {
  sprint: {
    name: string;
    totalStoryPoints: number;
    completedStoryPoints: number;
  };
  burndownChart: BurndownPoint[];
}

export default function Widget() {
  const sprintData = response.data as SprintData;
  const { sprint, burndownChart } = sprintData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              {sprint.name}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Completed {sprint.completedStoryPoints} of {sprint.totalStoryPoints} Story Points
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: burndownChart.map(point => point.remainingPoints),
                  color: '#4CAF50',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: burndownChart.map(point => point.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'points' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="points"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
